var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"스승님, 괜찮으십니까?","JPN":"師匠、大丈夫ですか？","ENG":"Are you okay, Master?","TWN":"師父，你沒事吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"크게 다치진 않았다. 그보다 저건…….","JPN":"大した怪我ではない。それよりあれは……","ENG":"It's only a scratch. But is that what I think it is…?","TWN":"小事，那是……"},"stage":{"bg":"CASTLE_01","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저건…… 주시윤 군과 닮아 보이는군요.","JPN":"あれは……アキヤマ君に似ていますね。","ENG":"That… looks a lot like Shiyoon.","TWN":"那是……他長得和周時雲好像。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"저 녀석들, 이런 곳에서 시간을 끌면서 뭘 꾸미나 했더니……","JPN":"あいつら、こんな所で時間を稼いで何を企んでいるかと思えば……","ENG":"So, this is why they've been buying all this time…","TWN":"那些傢伙！我還想他們在這種地方拖延時間是想做什麼……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"용인을 만들고 있었나?","JPN":"龍人を作っていたのか？","ENG":"They were creating a Dragonoid?","TWN":"原來是在製作龍人嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"잘 알고 있군요.","JPN":"よくご存知で。","ENG":"Ah, so you know of this.","TWN":"看來你也知道。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"세상에는 가끔 희석된, 극히 소량의 용의 피를 타고나는 자들이 있지요.","JPN":"世の中には稀に、希釈されたごく少量の龍の血を受け継いだ者がいます。","ENG":"A rare few are born with an infinitesimal amount of diluted Dragon Blood.","TWN":"世界上有一種人，他們的身上流著極少量稀釋過的龍血，"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"우리는 그런 자들을 용인이라 부릅니다.","JPN":"我々はそのような者を龍人と呼びます。","ENG":"We call them Dragonoids.","TWN":"我們稱那種人為龍人。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"확실히 구 관리국에도 환상종들의 혈통으로 이루어진 부대가 있었죠.","JPN":"確か旧管理局にも幻想種の血統で組まれた部隊がありましたね。","ENG":"The Old Administration also had a unit with agents with Bygone bloodlines.","TWN":"舊管理局裡確實也有以夢幻血統打造而成的部隊。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론 하나같이 강력한 이들이긴 했지만…….","JPN":"確かにみんな強力な存在でしたが……","ENG":"They were all pretty powerful, for sure…","TWN":"當然其中每一個都很強……"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금의 당신이나 저희들에 비하면 크게 특별할 것 없을 텐데요?","JPN":"今のあなたや僕たちに比べれば、さほど特別な存在でもないと思いますが。","ENG":"But I don't think they were all that formidable compared to you or us, were they?","TWN":"但和現在的我們和你應該沒有差太多吧？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"후후, 알면서도 모른 척 하는 건가요?","JPN":"ふふっ、まだ白を切るおつもりですか？","ENG":"Haha, must you insist on feigning such ignorance?","TWN":"呵呵～你是故意裝傻嗎？"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이건 그런 흔해빠진 하급 혼혈들과는 다릅니다.","JPN":"これはそんなありふれた下級混血とは違います。","ENG":"This creature is nothing like those vulgar half-breeds.","TWN":"他和那些混種的可是天差地別。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 용인은 최초의 용혈을 마셨다고 알려진 인간.","JPN":"この龍人は原初の龍血を飲んだとされる人間。","ENG":"This Dragonoid was forged from the very first man to drink Dragon Blood.","TWN":"這個龍人喝下的是最原始的龍血。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그 구도자의 업을 계승하는 자에게서 추출한 용혈로 제련해낸 것이니까요.","JPN":"その求道者のカルマを受け継ぐ者から抽出した龍血で製錬したものですからね。","ENG":"The Dragon Blood we extracted from he who inherited the Seeker's karma.","TWN":"是使用從求道者業障繼承者的身上抽取出來的龍血去煉製的。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"호오, 잘 감췄다고 생각했는데 벌써 거기까지 알아내셨군요.","JPN":"ほう、うまく隠したと思っていましたが、もうそこまで調べたのですね。","ENG":"Oh, I thought I had hidden that fact quite well from you, but you managed to figure it out.","TWN":"哈！我還以為藏得很好呢，沒想到你竟然知道這麼多！"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"운이 좋았죠. 마침 저희 중에도 용의 피에 조예가 깊은 분이 계셨으니까요.","JPN":"運が良かったです。私たちの中にも龍の血に造詣が深い方がいましたから。","ENG":"We were lucky. It just so happened that someone with immense knowledge about Dragon Blood was with us.","TWN":"我們運氣好，有位研究龍血相當透徹的人在我們當中。"},"stage":{"bg":"CASTLE_01","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};